using IntegraRP.Domain.Common;namespace IntegraRP.Domain.Tenancy;public sealed class Tenant:Entity{public Tenant(string nome,string slug){Nome=string.IsNullOrWhiteSpace(nome)?throw new ArgumentException("Nome obrigatório",nameof(nome)):nome;Slug=string.IsNullOrWhiteSpace(slug)?throw new ArgumentException("Slug obrigatório",nameof(slug)):slug;}public string Nome{get;}public string Slug{get;}public bool Ativo{get;private set;}=true;}
